/// <summary>
/// Abhinav - Cost distributions - 28-01-2025
/// Lookup for Dimension1
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(LedgerParameters, ETGCostDistributionLedgerDimension1), FormControlEventType::Lookup)]
public static void ETGCostDistributionLedgerDimension1_OnLookup(FormControl sender, FormControlEventArgs e)
{
    SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tableNum(DIMENSIONATTRIBUTE),sender);

    Query                   query = new Query();
    QueryBuildDataSource    queryBuildDataSource;
    QueryBuildRange         queryBuildRange;

    queryBuildDataSource = query.addDataSource(tableNum(DIMENSIONATTRIBUTE));

    sysTableLookup.addLookupfield(fieldNum(DIMENSIONATTRIBUTE,Name));


    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();

}

